INSERT INTO "public"."admin_bugs" ("id", "title", "description", "steps_to_reproduce", "status", "priority", "reported_by_user_id", "assigned_to_user_id", "resolved_at", "created_at", "updated_at") VALUES
	('ecb0835e-ac97-47f1-88a2-32310d517324', 'Contacts page fails to send', 'Should be able to send a contact to us.
Failed to send message. Please try again.', 'Go to contacts, put in a message then hit send.', 'open', 'medium', 'd3ae0172-7427-4ab9-b410-fad43c47e09d', NULL, NULL, '2026-02-27 16:07:10.841969+00', '2026-02-27 16:07:10.841969+00'),
	('93ad5878-9a6b-418e-b3c8-b2b9b3a28685', 'No duplication check on the name of a group.', 'When creating a group, it doesn''t check to see if that group already exists.', '1. Create a group with the same name as an existing group.  It lets you just create it.', 'closed', 'high', 'd3ae0172-7427-4ab9-b410-fad43c47e09d', NULL, '2026-02-27 16:09:00.167+00', '2026-02-26 21:33:50.140392+00', '2026-02-27 16:09:00.167+00'),
	('273de2bb-5d70-4304-a6b7-0d865ec2b9dd', 'Looking for Players is giving a "Failed to fetch players requests"', 'Need Players page says Failed to fetch player requests.', 'Go to the looking-for-players page.  yyfukoddeyiaxiufztdx.supabase.co/functions/v1/player-requests:1  Failed to load resource: the server responded with a status of 500 ()', 'closed', 'medium', 'd3ae0172-7427-4ab9-b410-fad43c47e09d', NULL, '2026-02-27 16:09:20.894+00', '2026-02-26 21:48:01.111143+00', '2026-02-27 16:09:20.894+00'),
	('4921dee6-ab5a-4ff9-9b9e-5aa8e3a98eab', 'When searching for Games, its not populating venues or location', 'When I search for a game, if I have selected a venue location it should automatically set that in the search.  If I have no venue location, the filter should auto populate with my location (if I have one) from my profile.', 'Go to the Games page.', 'open', 'medium', 'd3ae0172-7427-4ab9-b410-fad43c47e09d', NULL, NULL, '2026-02-27 16:14:32.91867+00', '2026-02-27 16:14:32.91867+00'),
	('f7f7f74a-253e-4a16-a3f2-666931589c96', 'Request to join group doesn''t work', 'When I try to join a group, it gives me a Failed to load resource: the server responded with a status of 403 ()', 'go a group that is request and click on the request button', 'open', 'high', 'd3ae0172-7427-4ab9-b410-fad43c47e09d', NULL, NULL, '2026-02-27 18:30:54.997265+00', '2026-02-27 18:30:54.997265+00'),
	('7d744170-1462-4b95-9b5f-dc6a48f728f7', 'When creating an account as username and email it fails to sign in', 'When I tried to create an account with username and password it gave an error of This sign-in method is not enabled.', 'goto the signup page and create a new account with a username and password, click create account.', 'open', 'high', 'd3ae0172-7427-4ab9-b410-fad43c47e09d', NULL, NULL, '2026-02-27 18:36:36.050884+00', '2026-02-27 18:36:36.050884+00');


