INSERT INTO "public"."admin_notes" ("id", "title", "content", "category", "is_pinned", "created_by_user_id", "created_at", "updated_at", "is_implemented") VALUES
	('964bf8dc-b155-4921-8b22-2ed088d3fb31', 'Improvement', 'Lets add Hot locations to the top, where someone can ask to add a location to a venue (Dice Tower West for instance).  Then when they add the location make sure we have additional fields where they can add optional location information (Hall, Room, Table etc).', 'Header', false, 'd3ae0172-7427-4ab9-b410-fad43c47e09d', '2026-02-26 19:11:00.614285+00', '2026-02-26 19:11:00.614285+00', false),
	('4673126a-bc0d-4082-894b-21e3295ba48a', 'Spinning 20 sided die', 'When something is loading, saving or working we should have an animation of a 20 sided die spinning and then eventually landing on 20.', 'general', false, 'd3ae0172-7427-4ab9-b410-fad43c47e09d', '2026-02-26 22:20:13.474542+00', '2026-02-27 16:03:17.198+00', true),
	('da9dd34a-18af-483e-9a20-316ddd98759f', 'Favorite games section in the profile', 'Should connect with BGG games and display them.', 'general', false, 'd3ae0172-7427-4ab9-b410-fad43c47e09d', '2026-02-26 21:52:46.454598+00', '2026-02-27 16:05:34.281+00', true),
	('b2ef1572-af6b-4dba-bd8b-464a615fa7c5', 'Should be able to set active location', 'By default the filter should use the City State and Zip you entered into your profile (if you have them set).  You should also be able to set your current location to an event location, in your profile.  That way the games filter option for finding games can default to that.  That way if you are at a convention and you want to look for a game or in the LFP section it can auto default to that event location.', 'general', false, 'd3ae0172-7427-4ab9-b410-fad43c47e09d', '2026-02-26 21:51:25.064688+00', '2026-02-27 16:15:29.137+00', true),
	('ee0a0c9c-e25a-4fdc-ab4f-bb4d801b41af', 'Contacts page', 'Lets add a contact us page, it should have the general contact information (if they are a user and signed in, it should auto populate their information into the form.  It should be in the footer.  Make sure it has a Captcha on it.', 'general', false, 'd3ae0172-7427-4ab9-b410-fad43c47e09d', '2026-02-26 21:45:27.538965+00', '2026-02-27 16:15:36.215+00', true),
	('37ee631e-4f3e-49e6-b678-6a714de36512', 'Home page statement', 'The home page should talk about our mission of bringing people who love board and card games together.', 'general', false, 'd3ae0172-7427-4ab9-b410-fad43c47e09d', '2026-02-26 21:43:26.679658+00', '2026-02-27 16:15:42.403+00', true),
	('a5c05626-a18a-403a-96b5-c21034845dd3', 'Past games', 'Past games should fall off and go to a history section found in the user profile settings for the user.  They should not show up in the Games I''m Hosting section.', 'general', false, 'd3ae0172-7427-4ab9-b410-fad43c47e09d', '2026-02-26 21:41:34.531813+00', '2026-02-27 16:15:51.683+00', true),
	('17915d5d-1b64-4c32-87bf-455b5a4e5c6d', 'Update text of Find Game Nights', 'We seem to be night centric.  Lets change the language to say "Find Games" from Find Game Nights on the games page.  Also change the Search game nights to "Search for games.  The button to host should be changed from "+ Host Game Night to Host a Game.  The main landing page should be changed from "Plan legendary game nights with your crew" to "Plan legendary games with your crew".  Change the Tonight to Today. Update the button of "+ Host a Game Night" to "+Host a Game" same changes on the dashboard.', 'general', false, 'd3ae0172-7427-4ab9-b410-fad43c47e09d', '2026-02-26 21:39:51.044531+00', '2026-02-27 16:16:04.279+00', true),
	('d73abab8-c550-4851-972d-4716c28c8b0b', 'Ads', 'We will need to implement an Ad system.  Lets talk about prices and implementation across the website and the iphone app.', 'general', false, 'd3ae0172-7427-4ab9-b410-fad43c47e09d', '2026-02-27 16:26:56.638942+00', '2026-02-27 16:26:56.638942+00', false),
	('15c2ea09-f918-482f-89bf-cbddb5549c49', 'paid tier', 'I want to have a paid tier.  This tier would have the ability to setup multiple games for an event.  It would include the host planning feature (which is only in groups currently).  This would include 5 games per. event, with the pro tier giving 10 games and the enterprise having unlimited games for an event.  Lets discuss pricing and implementation.', 'general', false, 'd3ae0172-7427-4ab9-b410-fad43c47e09d', '2026-02-27 16:30:21.486666+00', '2026-02-27 16:30:21.486666+00', false);


