INSERT INTO "public"."bgg_games_cache" ("bgg_id", "name", "year_published", "thumbnail_url", "image_url", "min_players", "max_players", "min_playtime", "max_playtime", "playing_time", "weight", "description", "categories", "mechanics", "cached_at", "search_vector", "bgg_rank", "num_ratings", "average_rating") VALUES
	(224517, 'Brass: Birmingham', 2018, 'https://cf.geekdo-images.com/x3zxjr-Vw5iU4yDPg70Jgw__small/img/o18rjEemoWaVru9Y2TyPwuIaRfE=/fit-in/200x150/filters:strip_icc()/pic3490053.jpg', 'https://cf.geekdo-images.com/x3zxjr-Vw5iU4yDPg70Jgw__original/img/FpyxH41Y6_ROoePAilPNEhXnzO8=/0x0/filters:format(jpeg)/pic3490053.jpg', 2, 4, 60, 120, 120, 3.86, 'Brass: Birmingham is an economic strategy game sequel to Martin Wallace''s 2007 masterpiece, Brass. Brass: Birmingham tells the story of competing entrepreneurs in Birmingham during the industrial revolution between the years of 1770 and 1870.

It offers a very different story arc and experience from its predecessor. As in its predecessor, you must develop, build and establish your industries and network in an effort to exploit low or high market demands. The game is played over two halves: the canal era (years 1770-1830) and the rail era (years 1830-1870). To win the game, score the most VPs. VPs are counted at the end of each half for the canals, rails and established (flipped) industry tiles.

Each round, players take turns according to the turn order track, receiving two actions to perform any of the following actions (found in the original game):

1) Build - Pay required resources and place an industry tile.
2) Network - Add a rail / canal link, expanding your network.
3) Develop - Increase the VP value of an industry.
4) Sell - Sell your cotton, manufactured goods and pottery.
5) Loan - Take a &pound;30 loan and reduce your income.

Brass: Birmingham also features a new sixth action:

6) Scout - Discard three cards and take a wild location and wild industry card. (This action replaces Double Action Build in original Brass.)', '{"Age of Reason",Economic,"Industry / Manufacturing",Post-Napoleonic,Trains,Transportation}', '{Chaining,"End Game Bonuses","Hand Management",Income,Loans,Market,"Multi-Use Cards","Network and Route Building",Ownership,Tags,"Tech Trees / Tech Tracks","Tile Placement","Turn Order: Stat-Based","Variable Set-up"}', '2026-02-27 16:16:56.11+00', '''-1830'':87C ''-1870'':94C ''1'':147C ''1770'':36C,86C ''1830'':93C ''1870'':38C ''2'':157C ''2007'':15C ''3'':167C ''30'':189C ''4'':176C ''5'':185C ''6'':203C ''accord'':126C ''action'':134C,141C,202C,218C,221C ''add'':159C ''age'':226B ''also'':197C ''arc'':45C ''base'':266B ''birmingham'':2A,4C,19C,27C,196C ''bonus'':240B ''brass'':1A,3C,17C,18C,195C,225C ''build'':58C,148C,222C,253B ''canal'':83C,114C,162C ''card'':207C,216C,249B ''chain'':237B ''compet'':24C ''cotton'':180C ''count'':105C ''demand'':74C ''develop'':57C,168C ''differ'':43C ''discard'':205C ''doubl'':220C ''econom'':7C,229B ''effort'':67C ''end'':108C,238B ''entrepreneur'':25C ''era'':84C,91C ''establish'':60C,117C ''expand'':164C ''experi'':47C ''exploit'':69C ''featur'':198C ''flip'':118C ''follow'':140C ''found'':142C ''game'':9C,76C,98C,146C,239B ''good'':182C ''half'':111C ''halv'':81C ''hand'':241B ''high'':72C ''incom'':194C,243B ''increas'':169C ''industri'':30C,62C,119C,155C,175C,215C,230B ''link'':163C ''loan'':186C,190C,244B ''locat'':212C ''low'':70C ''manag'':242B ''manufactur'':181C,231B ''market'':73C,245B ''martin'':12C ''masterpiec'':16C ''multi'':247B ''multi-us'':246B ''must'':56C ''napoleon'':234B ''network'':64C,158C,166C,250B ''new'':200C ''offer'':40C ''order'':130C,263B ''origin'':145C,224C ''ownership'':254B ''pay'':149C ''perform'':136C ''place'':153C ''placement'':261B ''play'':78C ''player'':123C ''post'':233B ''post-napoleon'':232B ''potteri'':184C ''predecessor'':50C,54C ''rail'':90C,115C,161C ''reason'':228B ''receiv'':132C ''reduc'':192C ''replac'':219C ''requir'':150C ''resourc'':151C ''revolut'':31C ''round'':122C ''rout'':252B ''score'':99C ''scout'':204C ''sell'':177C,178C ''sequel'':10C ''set'':269B ''set-up'':268B ''sixth'':201C ''stat'':265B ''stat-bas'':264B ''stori'':22C,44C ''strategi'':8C ''tag'':255B ''take'':124C,187C,209C ''tech'':256B,258B ''tell'':20C ''three'':206C ''tile'':120C,156C,260B ''track'':131C,259B ''train'':235B ''transport'':236B ''tree'':257B ''turn'':125C,129C,262B ''two'':80C,133C ''use'':248B ''valu'':172C ''variabl'':267B ''vp'':171C ''vps'':102C,103C ''wallac'':13C ''wild'':211C,214C ''win'':96C ''year'':34C,85C,92C', 1, 57013, 8.57),
	(167791, 'Terraforming Mars', 2016, 'https://cf.geekdo-images.com/wg9oOLcsKvDesSUdZQ4rxw__small/img/BTxqxgYay5tHJfVoJ2NF5g43_gA=/fit-in/200x150/filters:strip_icc()/pic3536616.jpg', 'https://cf.geekdo-images.com/wg9oOLcsKvDesSUdZQ4rxw__original/img/thIqWDnH9utKuoKVEUqveDixprI=/0x0/filters:format(jpeg)/pic3536616.jpg', 1, 5, 120, 120, 120, 3.27, 'In the 2400s, mankind begins to terraform the planet Mars. Giant corporations, sponsored by the World Government on Earth, initiate huge projects to raise the temperature, the oxygen level, and the ocean coverage until the environment is habitable. In Terraforming Mars, you play one of those corporations and work together in the terraforming process, but compete for getting victory points that are awarded not only for your contribution to the terraforming, but also for advancing human infrastructure throughout the solar system, and doing other commendable things.

As a player, you acquire unique project cards (from over two hundred different ones) by buying them to your hand. The cards can give you immediate bonuses, as well as increasing your production of different resources. Many cards also have requirements and they become playable when the temperature, oxygen, or ocean coverage increases enough. Buying cards is costly, so there is a balance between buying cards and actually playing them. Standard Projects are always available to complement your hand of cards. Your basic income, as well as your basic score, are based on your Terraform Rating. However, your income is boosted by your production, and VPs are also gained from many other sources.

You keep track of your production and resources on your player board.  The game uses six types of resources: MegaCredits, Steel, Titanium, Plants, Energy, and Heat. On the game board, you compete for the best places for your city tiles, ocean tiles, and greenery tiles. You also compete for different Milestones and Awards worth many VPs. Each round is called a generation and consists of the following phases:

1) Player order shifts clockwise.
2) Research phase: All players buy cards from four privately drawn.
